(()=>{const ROOM_PARAM='s',CACHE_PREFIX='coisas-mh-cache-',AUTHOR_KEY='coisas-mh-author',categoryIcons={Filme:'🎬',Lugar:'📍',Comida:'🍝','Rolê':'✨',Ideia:'💡',Outro:'📝'},$=(s,r=document)=>r.querySelector(s),$$=(s,r=document)=>[...r.querySelectorAll(s)],form=$('#ideaForm'),ideaInput=$('#ideaInput'),authorInput=$('#authorInput'),categoryInput=$('#categoryInput'),timingInput=$('#timingInput'),submitButton=$('#submitButton'),list=$('#ideasList'),template=$('#ideaTemplate'),emptyState=$('#emptyState'),openCount=$('#openCount'),openCountLabel=$('#openCountLabel'),searchInput=$('#searchInput'),syncStatus=$('#syncStatus'),toast=$('#toast');let filter='all',toastTimer,items=[],version=0,writing=false;const roomId=getOrCreateRoomId(),cacheKey=`${CACHE_PREFIX}${roomId}`;authorInput.value=localStorage.getItem(AUTHOR_KEY)==='MH'?'MH':'G';authorInput.addEventListener('change',()=>localStorage.setItem(AUTHOR_KEY,authorInput.value));function getOrCreateRoomId(){const url=new URL(location.href),current=url.searchParams.get(ROOM_PARAM);if(current&&/^[A-Za-z0-9_-]{24,64}$/.test(current))return current;const bytes=crypto.getRandomValues(new Uint8Array(24)),generated=btoa(String.fromCharCode(...bytes)).replaceAll('+','-').replaceAll('/','_').replaceAll('=','');url.searchParams.set(ROOM_PARAM,generated);history.replaceState(null,'',url);return generated}function apiUrl(){return`/api/room/${encodeURIComponent(roomId)}`}function setStatus(state,text){syncStatus.className=`sync-status ${state}`;$('span',syncStatus).textContent=text}function loadCache(){try{const saved=JSON.parse(localStorage.getItem(cacheKey));if(Array.isArray(saved?.items)){items=saved.items;version=Number(saved.version)||0;render()}}catch{}}function saveCache(){localStorage.setItem(cacheKey,JSON.stringify({items,version,savedAt:Date.now()}))}function applyState(state){if(!state||!Array.isArray(state.items))throw new Error('Resposta inválida');items=state.items;version=Number(state.version)||0;saveCache();render()}async function sync({quiet=false}={}){if(writing)return;if(!quiet)setStatus('loading','Atualizando');try{const response=await fetch(apiUrl(),{headers:{Accept:'application/json'},cache:'no-store'});if(!response.ok)throw new Error(`HTTP ${response.status}`);applyState(await response.json());setStatus('online','Sincronizado')}catch{setStatus('offline',items.length?'Usando cópia local':'Sem conexão')}}async function mutate(action,payload={}){writing=true;setStatus('loading','Salvando');try{const response=await fetch(apiUrl(),{method:'POST',headers:{'Content-Type':'application/json',Accept:'application/json'},body:JSON.stringify({action,payload,expectedVersion:version})}),body=await response.json().catch(()=>({}));if(!response.ok)throw new Error(body.error||`HTTP ${response.status}`);applyState(body);setStatus('online','Sincronizado');return true}catch(error){setStatus('offline','Não foi salvo');showToast(error.message==='conflict'?'A lista mudou. Atualizando…':'Não deu para salvar agora');await sync({quiet:true});return false}finally{writing=false}}function showToast(message){clearTimeout(toastTimer);toast.textContent=message;toast.classList.add('show');toastTimer=setTimeout(()=>toast.classList.remove('show'),2400)}function formatDate(value){return new Intl.DateTimeFormat('pt-BR',{day:'2-digit',month:'short'}).format(new Date(value)).replace('.','')}function visibleItems(){const term=searchInput.value.trim().toLocaleLowerCase('pt-BR');return items.filter(item=>{const statusMatches=filter==='all'||(filter==='done'?item.done:!item.done),searchMatches=!term||`${item.text} ${item.category} ${item.timing} ${item.author}`.toLocaleLowerCase('pt-BR').includes(term);return statusMatches&&searchMatches})}function render(){list.innerHTML='';const filtered=visibleItems();filtered.forEach(item=>{const fragment=template.content.cloneNode(true),card=$('.idea-card',fragment),checkButton=$('.check-button',fragment),text=$('.idea-text',fragment),author=$('.author-badge',fragment),category=$('.category-badge',fragment),timing=$('.timing-badge',fragment),time=$('time',fragment),menuButton=$('.menu-button',fragment),menu=$('.idea-menu',fragment);card.dataset.id=item.id;card.classList.toggle('done',item.done);checkButton.setAttribute('aria-label',item.done?'Marcar como pendente':'Marcar como feita');text.textContent=item.text;author.textContent=item.author==='MH'?'MH':'G';category.textContent=`${categoryIcons[item.category]||'📝'} ${item.category}`;timing.textContent=item.timing;time.textContent=formatDate(item.createdAt);time.dateTime=item.createdAt;checkButton.addEventListener('click',async()=>{await mutate('toggle',{id:item.id})});menuButton.addEventListener('click',event=>{event.stopPropagation();$$('.idea-menu').forEach(current=>{if(current!==menu)current.hidden=true});menu.hidden=!menu.hidden});menu.addEventListener('click',event=>{const action=event.target.dataset.action;if(action==='edit')editItem(item);if(action==='delete')deleteItem(item)});list.appendChild(fragment)});const pending=items.filter(item=>!item.done).length;openCount.textContent=String(pending);openCountLabel.textContent=pending===1?' ideia esperando':' ideias esperando';emptyState.hidden=filtered.length!==0}async function editItem(item){const next=window.prompt('Editar ideia:',item.text);if(next===null)return;const clean=next.trim();if(!clean)return showToast('A ideia não pode ficar vazia');if(await mutate('edit',{id:item.id,text:clean.slice(0,180)}))showToast('Ideia atualizada')}async function deleteItem(item){if(!window.confirm(`Apagar “${item.text}”?`))return;if(await mutate('delete',{id:item.id}))showToast('Ideia apagada')}async function shareAccess(){const data={title:'Coisas para fazer com a MH',text:'Entra na nossa lista compartilhada:',url:location.href};try{if(navigator.share)await navigator.share(data);else{await navigator.clipboard.writeText(location.href);showToast('Link de acesso copiado')}}catch(error){if(error?.name!=='AbortError')showToast('Não deu para compartilhar')}}function exportList(){const data=JSON.stringify({version:1,roomVersion:version,exportedAt:new Date().toISOString(),items},null,2),blob=new Blob([data],{type:'application/json'}),url=URL.createObjectURL(blob),link=document.createElement('a');link.href=url;link.download=`coisas-mh-${new Date().toISOString().slice(0,10)}.json`;link.click();URL.revokeObjectURL(url);showToast('Backup exportado')}async function importList(file){try{const payload=JSON.parse(await file.text()),imported=Array.isArray(payload)?payload:payload.items;if(!Array.isArray(imported))throw new Error('Formato inválido');if(!window.confirm('Substituir a lista compartilhada pelo conteúdo desse arquivo?'))return;if(await mutate('replace',{items:imported}))showToast('Lista importada')}catch{showToast('Esse arquivo não parece ser uma lista válida')}}form.addEventListener('submit',async event=>{event.preventDefault();const text=ideaInput.value.trim();if(!text)return;submitButton.disabled=true;const saved=await mutate('add',{text,author:authorInput.value,category:categoryInput.value,timing:timingInput.value});submitButton.disabled=false;if(saved){ideaInput.value='';ideaInput.focus();showToast('Entrou na lista ♡')}});$('#focusInput').addEventListener('click',()=>ideaInput.focus());$('#shareButton').addEventListener('click',shareAccess);$('#exportButton').addEventListener('click',exportList);$('#importInput').addEventListener('change',event=>{const[file]=event.target.files;if(file)importList(file);event.target.value=''});$('#clearDoneButton').addEventListener('click',async()=>{const count=items.filter(item=>item.done).length;if(!count)return showToast('Nenhuma ideia feita para limpar');if(!window.confirm(`Apagar ${count} ${count===1?'ideia feita':'ideias feitas'}?`))return;if(await mutate('clearDone'))showToast('Feitas removidas')});$$('.filter-chip').forEach(button=>button.addEventListener('click',()=>{filter=button.dataset.filter;$$('.filter-chip').forEach(chip=>chip.classList.toggle('active',chip===button));render()}));searchInput.addEventListener('input',render);document.addEventListener('click',()=>$$('.idea-menu').forEach(menu=>menu.hidden=true));window.addEventListener('online',()=>sync());window.addEventListener('offline',()=>setStatus('offline','Sem conexão'));if('serviceWorker'in navigator)window.addEventListener('load',()=>navigator.serviceWorker.register('./sw.js').catch(()=>{}));loadCache();render();sync();setInterval(()=>sync({quiet:true}),5000)})();
